-- 1. CE Ferulic
UPDATE products SET
  image_url = '/images/products/skinceuticals/ce-ferulic.jpg',
  price = 182.00,
  size = '30ml / 1 fl oz',
  description = 'CE Ferulic® is the gold-standard antioxidant serum by SkinCeuticals, combining 15% pure L-ascorbic acid (vitamin C), 1% alpha tocopherol (vitamin E), and 0.5% ferulic acid in a patented formula that delivers 8 times the skin''s natural photoprotection against environmental damage. CE Ferulic is the most-studied and most-recommended vitamin C serum in dermatology, with over two decades of published clinical research proving its ability to reduce oxidative stress, brighten the complexion, firm the skin, and diminish the appearance of fine lines and wrinkles. Available exclusively at RELUXE Med Spa in Westfield and Carmel, Indiana.

