  faq = '[{"q":"Why is CE Ferulic so expensive compared to other vitamin C serums?","a":"CE Ferulic uses patented technology that took years to develop. The specific combination of 15% L-ascorbic acid at pH 2.0-3.5, 1% vitamin E, and 0.5% ferulic acid creates exponential synergy—8x more photoprotection than vitamin C alone. Drugstore vitamin C serums cannot replicate this stability or efficacy."},{"q":"Why does CE Ferulic have that smell?","a":"The slight hot-dog-like scent comes from pure L-ascorbic acid at therapeutic concentration. It indicates potency, not spoilage. The scent dissipates within seconds of application and does not affect performance."},{"q":"Can I buy CE Ferulic online?","a":"SkinCeuticals is a professional-only brand. CE Ferulic is available exclusively through authorized providers like RELUXE Med Spa. Visit our Westfield or Carmel location for a complimentary skin consultation and purchase."},{"q":"How long does one bottle of CE Ferulic last?","a":"With daily use of 4-5 drops each morning, one 30ml bottle lasts approximately 2-3 months. Store in a cool, dark place—CE Ferulic should remain golden or light amber in color."}]'::JSONB,
  staff_picks = '{"westfield":"The single most impactful addition to any skincare routine. Our Westfield team has seen CE Ferulic transform dull, aging skin across Hamilton County—it''s the product we''d keep if we could only keep one.","carmel":"Every skincare routine at RELUXE Carmel starts with CE Ferulic. Apply before your Colorescience SPF every morning—it''s 8x more photoprotection than vitamin C alone. The gold standard for Indiana patients serious about their skin."}'::JSONB,
  related_services = ARRAY['microneedling', 'chemical-peels', 'ipl-photofacial']
